using CertDesk.Models; using CertDesk.Services;
namespace CertDesk.Forms;
public sealed class EmployeesView:UserControl
{ readonly CurrentUser user; readonly EmployeeService service; readonly DataGridView grid=Ui.Grid(); readonly TextBox search=Ui.TextBox(); readonly ComboBox state=Ui.Combo();
 public EmployeesView(CurrentUser user){this.user=user; service=new(user); var top=new FlowLayoutPanel{Dock=DockStyle.Top,Height=48}; state.Items.AddRange(["Все","Активные","Архивные"]); state.SelectedIndex=1; var add=Ui.Button("Добавить"); var edit=Ui.Button("Изменить"); var arch=Ui.Button("Архивировать"); var refresh=Ui.Button("Обновить"); top.Controls.AddRange([Ui.Label("Поиск"),search,state,add,edit,arch,refresh]); Controls.Add(grid); Controls.Add(top); search.TextChanged+=(_,_)=>LoadData(); state.SelectedIndexChanged+=(_,_)=>LoadData(); refresh.Click+=(_,_)=>LoadData(); add.Click+=(_,_)=>Open(0); edit.Click+=(_,_)=>Open(Id()); arch.Click+=(_,_)=>{if(!Can())return; service.Archive(Id());LoadData();}; if(!AuthService.CanEdit(user)){add.Visible=edit.Visible=arch.Visible=false;} LoadData();}
 int Id()=>grid.CurrentRow==null?0:Convert.ToInt32(grid.CurrentRow.Cells["id"].Value); bool Can(){if(!AuthService.CanEdit(user)){MessageBox.Show("Недостаточно прав для выполнения операции.");return false;} return Id()>0;} void Open(int id){if(!AuthService.CanEdit(user)){MessageBox.Show("Недостаточно прав для выполнения операции.");return;} if(id!=0&&Id()==0)return; using var f=new EmployeeEditForm(service.Get(id)??new Employee(),service); if(f.ShowDialog()==DialogResult.OK)LoadData();} void LoadData(){grid.DataSource=service.Search(search.Text,state.Text); if(grid.Columns.Contains("id"))grid.Columns["id"].Visible=false;}
}
